-- 创建数据库
CREATE DATABASE IF NOT EXISTS cat_adoption CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE cat_adoption;

-- 用户表
CREATE TABLE IF NOT EXISTS users (
    id INT PRIMARY KEY AUTO_INCREMENT,
    username VARCHAR(50) UNIQUE NOT NULL,
    password VARCHAR(255) NOT NULL,
    email VARCHAR(100) UNIQUE,
    role ENUM('admin', 'user') DEFAULT 'user',
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

-- 猫咪信息表
CREATE TABLE IF NOT EXISTS cats (
    id INT PRIMARY KEY AUTO_INCREMENT,
    name VARCHAR(50) NOT NULL,
    code VARCHAR(20) UNIQUE NOT NULL,
    breed VARCHAR(50),
    age VARCHAR(20),
    personality TEXT,
    habits TEXT,
    image_url VARCHAR(255),
    category VARCHAR(50) DEFAULT '普通',  -- 猫咪种类分类
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

-- 领养申请表
CREATE TABLE IF NOT EXISTS adoption_applications (
    id INT PRIMARY KEY AUTO_INCREMENT,
    user_id INT NOT NULL,
    cat_id INT NOT NULL,
    -- 申请人信息
    full_name VARCHAR(50) NOT NULL,
    age INT NOT NULL,
    occupation VARCHAR(100),
    housing VARCHAR(100) NOT NULL,  -- 住房情况
    pet_experience TEXT,             -- 养宠经验
    agree_visit BOOLEAN DEFAULT FALSE,  -- 是否同意回访
    agree_neuter BOOLEAN DEFAULT FALSE, -- 是否同意绝育
    -- 申请状态
    status ENUM('pending', 'approved', 'rejected') DEFAULT 'pending',
    admin_remark TEXT,
    submitted_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    reviewed_at TIMESTAMP NULL,
    FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE,
    FOREIGN KEY (cat_id) REFERENCES cats(id) ON DELETE CASCADE
);

-- 预约表（改进版，支持多人预约同一时间段）
CREATE TABLE IF NOT EXISTS appointments (
    id INT PRIMARY KEY AUTO_INCREMENT,
    application_id INT NOT NULL,     -- 关联领养申请
    cat_id INT NOT NULL,
    user_id INT NOT NULL,
    appointment_date DATE NOT NULL,
    appointment_time VARCHAR(20) NOT NULL,
    status ENUM('pending', 'confirmed', 'completed', 'cancelled') DEFAULT 'pending',
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (application_id) REFERENCES adoption_applications(id) ON DELETE CASCADE,
    FOREIGN KEY (cat_id) REFERENCES cats(id) ON DELETE CASCADE,
    FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
);

-- 时间段容量表（用于控制每个时间段最多5人）
CREATE TABLE IF NOT EXISTS time_slot_capacity (
    id INT PRIMARY KEY AUTO_INCREMENT,
    cat_id INT NOT NULL,
    appointment_date DATE NOT NULL,
    appointment_time VARCHAR(20) NOT NULL,
    current_count INT DEFAULT 0,     -- 当前预约人数
    max_capacity INT DEFAULT 5,       -- 最大容量
    UNIQUE KEY unique_slot (cat_id, appointment_date, appointment_time),
    FOREIGN KEY (cat_id) REFERENCES cats(id) ON DELETE CASCADE
);

